globals_css.content:
@tailwind base;
@tailwind components;
@tailwind utilities;

/* react-day-picker v8 base styles */
@import 'react-day-picker/dist/style.css';

/* calendo-* utility classes used by pre-built components */
@layer utilities {
  .calendo-bg { background-color: #0F0F0F; }
  .calendo-surface { background-color: #1A1A1A; }
  .calendo-accent { background-color: #E1306C; }
  .calendo-border { border-color: #2A2A2A; }
  .calendo-text { color: #F5F5F5; }
  .calendo-muted { color: #888888; }
}

/* Global dark background */
body {
  background-color: #0F0F0F;
  color: #F5F5F5;
  font-family: system-ui, -apple-system, sans-serif;
}

lib_utils_ts.full_content:
import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}
